Here's the XAML and ViewModel setup:

**XAML — wrap CollectionView in RefreshView for pull-to-refresh:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <VisualStateManager.VisualStateGroups>
                        <VisualStateGroup Name="CommonStates">
                            <VisualState Name="Normal">
                                <VisualState.Setters>
                                    <Setter Property="BackgroundColor" Value="Transparent" />
                                </VisualState.Setters>
                            </VisualState>
                            <VisualState Name="Selected">
                                <VisualState.Setters>
                                    <Setter Property="BackgroundColor" Value="{StaticResource Primary}" />
                                </VisualState.Setters>
                            </VisualState>
                        </VisualStateGroup>
                    </VisualStateManager.VisualStateGroups>
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found." HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel bindings needed:**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    // Pull-to-refresh: reload from API, then set IsRefreshing = false
    [RelayCommand]
    private async Task RefreshAsync()
    {
        var data = await _api.GetItemsAsync();
        MainThread.BeginInvokeOnMainThread(() =>
        {
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        });
        IsRefreshing = false;
    }

    // Selection: navigate to detail, then clear selection
    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;
        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });
        CurrentItem = null; // reset so user can re-select same item
    }
}
```

**Key points:**

| Concept | What to bind | Notes |
|---|---|---|
| **Data source** | `ObservableCollection<T>` → `ItemsSource` | Never use `List<T>` — UI won't update |
| **Selection** | `SelectedItem` (TwoWay) + `SelectionChangedCommand` | Set `CurrentItem = null` after navigation so the same item can be re-selected |
| **Pull-to-refresh** | `RefreshView.IsRefreshing` (TwoWay) + `Command` | You **must** set `IsRefreshing = false` when done or the spinner won't stop |
| **Thread safety** | Update collections on UI thread | Use `MainThread.BeginInvokeOnMainThread` |
| **Item template** | No `ViewCell` — use `Grid`, `StackLayout`, etc. | Set `x:DataType` for compiled bindings |
